INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('programacion', 'eso', '{1}', 'Un algoritmo es una secuencia de instrucciones ordenadas para resolver un problema concreto'),
('programacion', 'eso', '{1}', 'Scratch utiliza bloques de colores que se encajan como piezas de un rompecabezas'),
('programacion', 'eso', '{1}', 'La secuencia es el orden en el que el ordenador ejecuta las instrucciones del programa'),
('programacion', 'eso', '{1}', 'Un sprite es un personaje o elemento gráfico que se mueve por el escenario en Scratch'),
('programacion', 'eso', '{1}', 'El escenario de Scratch es el fondo donde ocurren las acciones de nuestro programa'),
('programacion', 'eso', '{1}', 'Los bloques de movimiento permiten desplazar al sprite por la pantalla en cualquier dirección'),
('programacion', 'eso', '{1}', 'Un evento es una acción que inicia la ejecución de un grupo de bloques en el programa'),
('programacion', 'eso', '{1}', 'La bandera verde de Scratch sirve para iniciar la ejecución del programa principal'),
('programacion', 'eso', '{1}', 'Los bloques de apariencia cambian el disfraz y el tamaño del sprite en pantalla'),
('programacion', 'eso', '{1}', 'Un mensaje en Scratch permite que dos sprites se comuniquen entre sí durante el programa'),
('programacion', 'eso', '{1}', 'El bloque repetir ejecuta las instrucciones que contiene un número determinado de veces'),
('programacion', 'eso', '{1}', 'La descomposición consiste en dividir un problema grande en partes más pequeñas y sencillas'),
('programacion', 'eso', '{1}', 'Un diagrama de flujo representa de forma visual los pasos de un algoritmo con flechas'),
('programacion', 'eso', '{1}', 'El pensamiento computacional nos ayuda a resolver problemas de forma lógica y ordenada'),
('programacion', 'eso', '{1}', 'Los bloques de sonido permiten reproducir música y efectos dentro de un proyecto de Scratch'),
('programacion', 'eso', '{1}', 'Un programa es un conjunto de instrucciones que el ordenador puede ejecutar de forma automática'),
('programacion', 'eso', '{1}', 'La abstracción consiste en quedarse solo con la información importante e ignorar los detalles'),
('programacion', 'eso', '{1}', 'El reconocimiento de patrones nos permite encontrar similitudes entre diferentes problemas'),
('programacion', 'eso', '{1}', 'Un bucle infinito repite las instrucciones sin parar hasta que detenemos el programa manualmente'),
('programacion', 'eso', '{1}', 'El bloque condicional si-entonces ejecuta unas instrucciones solo cuando se cumple una condición'),
('programacion', 'eso', '{1}', 'Los sensores de Scratch detectan si el sprite toca un borde o choca con otro objeto'),
('programacion', 'eso', '{1}', 'Un fondo del escenario se puede cambiar usando los bloques de apariencia del escenario'),
('programacion', 'eso', '{1}', 'Las coordenadas X e Y indican la posición exacta del sprite dentro del escenario'),
('programacion', 'eso', '{1}', 'El eje X representa la posición horizontal y el eje Y la posición vertical en pantalla'),
('programacion', 'eso', '{1}', 'Un error de lógica hace que el programa funcione pero no haga lo que esperábamos'),
('programacion', 'eso', '{1}', 'El depurador nos ayuda a encontrar errores revisando el programa paso a paso con cuidado'),
('programacion', 'eso', '{1}', 'Las instrucciones de un algoritmo deben ser claras y no dejar lugar a la ambigüedad'),
('programacion', 'eso', '{1}', 'Un proyecto de Scratch puede contener varios sprites que interactúan entre sí al ejecutarse'),
('programacion', 'eso', '{1}', 'Los operadores matemáticos permiten realizar sumas restas multiplicaciones y divisiones en el código'),
('programacion', 'eso', '{1}', 'El bloque preguntar muestra un cuadro de texto donde el usuario puede escribir su respuesta'),
('programacion', 'eso', '{1}', 'La variable respuesta almacena lo que el usuario escribió en el último cuadro de pregunta'),
('programacion', 'eso', '{1}', 'Un clon en Scratch es una copia temporal del sprite que puede actuar de forma independiente'),
('programacion', 'eso', '{1}', 'Los bloques de lápiz permiten dibujar líneas y figuras geométricas en el escenario de Scratch'),
('programacion', 'eso', '{1}', 'El bloque esperar detiene la ejecución durante unos segundos antes de continuar con la siguiente instrucción'),
('programacion', 'eso', '{1}', 'Las extensiones de Scratch añaden funciones nuevas como traducción de texto o síntesis de voz'),
('programacion', 'eso', '{1}', 'Un algoritmo debe tener un inicio claro y un final definido para que funcione correctamente'),
('programacion', 'eso', '{1}', 'La creatividad es fundamental para diseñar programas originales que resuelvan problemas reales'),
('programacion', 'eso', '{1}', 'El pensamiento lógico nos permite encadenar instrucciones en el orden correcto sin saltarnos pasos'),
('programacion', 'eso', '{1}', 'Un juego en Scratch necesita un sistema de puntuación para motivar al jugador a mejorar'),
('programacion', 'eso', '{1}', 'Los bloques de control deciden cuántas veces se repiten las acciones o cuándo se ejecutan'),
('programacion', 'eso', '{1}', 'Compartir un proyecto en la comunidad de Scratch permite que otros usuarios lo vean y remixen'),
('programacion', 'eso', '{1}', 'El diseño de un videojuego empieza por definir las reglas y los objetivos del juego'),
('programacion', 'eso', '{1}', 'Un algoritmo de la vida cotidiana es seguir una receta de cocina paso a paso sin saltarse nada'),
('programacion', 'eso', '{1}', 'La iteración permite mejorar un programa repitiendo el proceso de diseño prueba y corrección'),
('programacion', 'eso', '{1}', 'Los bloques de operadores comparan valores y devuelven verdadero o falso según la condición'),
('programacion', 'eso', '{1}', 'El trabajo en equipo facilita la creación de proyectos de programación más grandes y completos'),
('programacion', 'eso', '{1}', 'Un personaje animado en Scratch cambia de disfraz rápidamente para simular el movimiento'),
('programacion', 'eso', '{1}', 'La programación visual con bloques es más sencilla porque evita los errores de escritura del código'),
('programacion', 'eso', '{1}', 'El orden de las instrucciones es fundamental porque cambiar un paso puede alterar todo el resultado'),
('programacion', 'eso', '{1}', 'Un buen programador prueba su código varias veces para asegurarse de que funciona en todos los casos');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('programacion', 'eso', '{2}', 'Una variable de tipo entero almacena números sin decimales como la edad o la puntuación del juego'),
('programacion', 'eso', '{2}', 'Las cadenas de texto son secuencias de caracteres encerradas entre comillas dobles o simples'),
('programacion', 'eso', '{2}', 'El bucle for repite un bloque de código un número determinado de veces usando un contador'),
('programacion', 'eso', '{2}', 'El bucle while ejecuta las instrucciones repetidamente mientras la condición indicada sea verdadera'),
('programacion', 'eso', '{2}', 'Una función recibe datos de entrada los procesa y devuelve un resultado como salida'),
('programacion', 'eso', '{2}', 'Los parámetros de una función son los valores que le pasamos para que trabaje con ellos'),
('programacion', 'eso', '{2}', 'El valor de retorno es el dato que la función devuelve al programa principal tras ejecutarse'),
('programacion', 'eso', '{2}', 'Un condicional anidado es una estructura si-entonces dentro de otra estructura si-entonces'),
('programacion', 'eso', '{2}', 'El operador AND devuelve verdadero solo cuando las dos condiciones que conecta son verdaderas'),
('programacion', 'eso', '{2}', 'El operador OR devuelve verdadero cuando al menos una de las dos condiciones es verdadera'),
('programacion', 'eso', '{2}', 'El operador NOT invierte el valor lógico convirtiendo verdadero en falso y viceversa'),
('programacion', 'eso', '{2}', 'Un acumulador es una variable que va sumando valores dentro de un bucle para obtener un total'),
('programacion', 'eso', '{2}', 'El contador es una variable que se incrementa en uno cada vez que el bucle completa una vuelta'),
('programacion', 'eso', '{2}', 'La estructura si-si no permite ejecutar un bloque de código u otro según el resultado de la condición'),
('programacion', 'eso', '{2}', 'Un diagrama de flujo utiliza rombos para representar decisiones y rectángulos para las acciones'),
('programacion', 'eso', '{2}', 'La entrada de datos permite al usuario introducir información que el programa necesita para funcionar'),
('programacion', 'eso', '{2}', 'La salida de datos muestra al usuario los resultados que el programa ha calculado o procesado'),
('programacion', 'eso', '{2}', 'Los operadores de comparación permiten verificar si dos valores son iguales mayores o menores'),
('programacion', 'eso', '{2}', 'Una variable booleana solo puede contener dos valores posibles que son verdadero o falso'),
('programacion', 'eso', '{2}', 'El alcance de una variable determina en qué partes del programa puede ser utilizada'),
('programacion', 'eso', '{2}', 'La modularidad divide el programa en funciones independientes que se pueden probar por separado'),
('programacion', 'eso', '{2}', 'Un error de sintaxis ocurre cuando el programador no respeta las reglas gramaticales del lenguaje'),
('programacion', 'eso', '{2}', 'Las pruebas del programa verifican que todas las funciones producen los resultados esperados correctamente'),
('programacion', 'eso', '{2}', 'La tabla de seguimiento permite rastrear el valor de las variables durante la ejecución del algoritmo'),
('programacion', 'eso', '{2}', 'Un número aleatorio generado por el programa sirve para crear situaciones impredecibles en los juegos'),
('programacion', 'eso', '{2}', 'El tipo de dato float almacena números con parte decimal como la temperatura o el precio'),
('programacion', 'eso', '{2}', 'La conversión de tipos transforma un dato de un formato a otro como de texto a número entero'),
('programacion', 'eso', '{2}', 'Un programa interactivo responde a las acciones del usuario en tiempo real mediante eventos'),
('programacion', 'eso', '{2}', 'La estructura repetir hasta ejecuta las instrucciones y luego comprueba si debe detenerse'),
('programacion', 'eso', '{2}', 'Los comentarios del código son notas que el programador escribe para explicar lo que hace cada parte'),
('programacion', 'eso', '{2}', 'Una librería es un conjunto de funciones ya programadas que podemos reutilizar en nuestros proyectos'),
('programacion', 'eso', '{2}', 'La eficiencia del código se mide por la rapidez y la cantidad de recursos que necesita para ejecutarse'),
('programacion', 'eso', '{2}', 'El operador módulo devuelve el resto de una división entera y es útil para detectar números pares'),
('programacion', 'eso', '{2}', 'Una animación por código se crea cambiando las propiedades de un objeto en cada fotograma del bucle'),
('programacion', 'eso', '{2}', 'La programación por bloques enseña los mismos conceptos que la programación textual de forma visual'),
('programacion', 'eso', '{2}', 'Un menú de opciones permite al usuario elegir entre varias acciones disponibles dentro del programa'),
('programacion', 'eso', '{2}', 'La validación de datos comprueba que la información introducida por el usuario es correcta y válida'),
('programacion', 'eso', '{2}', 'Un bucle controlado por centinela se detiene cuando el usuario introduce un valor especial de salida'),
('programacion', 'eso', '{2}', 'El flujo de ejecución describe el camino que sigue el programa desde la primera hasta la última instrucción'),
('programacion', 'eso', '{2}', 'Las constantes son valores que se definen una vez y no pueden modificarse durante la ejecución'),
('programacion', 'eso', '{2}', 'Un algoritmo de búsqueda lineal recorre todos los elementos de la lista hasta encontrar el buscado'),
('programacion', 'eso', '{2}', 'La legibilidad del código mejora cuando usamos nombres descriptivos para las variables y funciones'),
('programacion', 'eso', '{2}', 'Un array permite guardar varios datos del mismo tipo en una sola variable organizada por posiciones'),
('programacion', 'eso', '{2}', 'El índice de un array indica la posición donde se encuentra cada elemento dentro de la estructura'),
('programacion', 'eso', '{2}', 'La depuración paso a paso permite observar cómo cambian las variables en cada línea del programa'),
('programacion', 'eso', '{2}', 'Un programa debe manejar los errores del usuario mostrando mensajes claros en lugar de fallar'),
('programacion', 'eso', '{2}', 'La planificación del programa incluye definir los objetivos las entradas las salidas y el proceso'),
('programacion', 'eso', '{2}', 'El operador de concatenación une dos cadenas de texto para formar una nueva cadena más larga'),
('programacion', 'eso', '{2}', 'La estructura switch permite elegir entre múltiples opciones según el valor de una variable'),
('programacion', 'eso', '{2}', 'Un buen algoritmo debe ser finito correcto y lo más eficiente posible en el uso de recursos');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('programacion', 'eso', '{3}', 'Python utiliza la función print para mostrar mensajes y resultados por la consola del programa'),
