('programacion', 'eso', '{3}', 'El módulo turtle de Python permite crear gráficos y animaciones moviendo una tortuga por la pantalla'),
('programacion', 'eso', '{3}', 'La documentación de una función se escribe dentro de comillas triples justo debajo de la definición'),
('programacion', 'eso', '{3}', 'Los diccionarios anidados permiten crear estructuras de datos complejas con varios niveles de profundidad'),
('programacion', 'eso', '{3}', 'El método items del diccionario devuelve todos los pares clave-valor para recorrerlos en un bucle'),
('programacion', 'eso', '{3}', 'La programación funcional utiliza funciones puras que no modifican el estado externo del programa'),
('programacion', 'eso', '{3}', 'El método strip elimina los espacios en blanco al inicio y al final de una cadena de texto'),
('programacion', 'eso', '{3}', 'Las pruebas unitarias verifican que cada función individual del programa produce el resultado esperado');
INSERT INTO ordena_frases (subject_id, level, grades, sentence) VALUES
('programacion', 'eso', '{4}', 'Una clase en programación orientada a objetos define las propiedades y los métodos de un tipo de objeto'),
('programacion', 'eso', '{4}', 'Un objeto es una instancia concreta de una clase que posee valores propios para sus atributos'),
('programacion', 'eso', '{4}', 'El constructor de una clase es el método especial que se ejecuta automáticamente al crear un objeto'),
('programacion', 'eso', '{4}', 'La herencia permite crear una clase nueva que reutiliza los atributos y métodos de otra ya existente'),
('programacion', 'eso', '{4}', 'El polimorfismo permite que diferentes clases respondan de forma distinta al mismo nombre de método'),
('programacion', 'eso', '{4}', 'El encapsulamiento oculta los detalles internos de un objeto y solo expone lo estrictamente necesario'),
('programacion', 'eso', '{4}', 'Una base de datos relacional organiza la información en tablas relacionadas mediante claves primarias y foráneas'),
